('palermo', 'politeama', 'teatro-massimo-palermo', 'Teatro Massimo', '{"en":"Family-ready guided visits in the city center.","it":"Visite guidate family-ready nel cuore della citta."}', '{"en":"A reliable culture pick when you want one clear slot, short duration, and a strong Palermo identity.","it":"Una scelta culturale affidabile quando serve uno slot chiaro, una durata breve e una forte identita palermitana."}', 'Piazza Verdi, Palermo', 38.1228, 13.3578, '["Central location","Indoor","Family ticket"]', '["Italian","English"]', '["guided-visit"]', '["culture"]', '["teatro-massimo-booking"]', '{"en":"Official guided-visit information checked from the theater website.","it":"Informazioni ufficiali sulle visite guidate controllate dal sito del teatro."}', 'https://www.teatromassimo.it/', '2026-03-29T11:00:00+02:00'),
('palermo', 'politeama', 'planetario-palermo-place', 'Planetario di Palermo', '{"en":"Weekend astronomy with fixed family-friendly turni.","it":"Astronomia nel weekend con turni family-friendly."}', '{"en":"A clean science option for families who want a repeatable weekend ritual.","it":"Un opzione scientifica pulita per famiglie che vogliono un rito del weekend ripetibile."}', 'Piazza San Francesco di Paola 18, Palermo', 38.1244, 13.3517, '["Indoor dome","Weekend schedule","Museum visit"]', '["Italian"]', '["planetarium-show"]', '["stem"]', '["planetario-contact"]', '{"en":"Weekend public timetable monitored from the official planetarium channels.","it":"Timetable pubblico del weekend monitorato dai canali ufficiali del planetario."}', 'https://www.planetariopalermo.it/', '2026-03-29T11:00:00+02:00'),
